#!/usr/bin/env bash
# 0-1-1-10-10-100.sh — 商家从入驻到稳定输出（0→1 / 1→10 / 10→100 三阶段全生命周期） SOP walkthrough for 抖音直播带货 (商家 / 主播 / 直播间运营 + 千川 / 巨量引擎广告投放 + 选品 + 流量场承接 + 合规).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="抖音直播带货 (商家 / 主播 / 直播间运营 + 千川 / 巨量引擎广告投放 + 选品 + 流量场承接 + 合规)"
WORKFLOW="商家从入驻到稳定输出（0→1 / 1→10 / 10→100 三阶段全生命周期）"

usage() {
  cat <<EOF
0-1-1-10-10-100.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./0-1-1-10-10-100.sh             # interactive
  ./0-1-1-10-10-100.sh --dry-run
  ./0-1-1-10-10-100.sh --json
  ./0-1-1-10-10-100.sh --explain
  ./0-1-1-10-10-100.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "商家从入驻到稳定输出（0→1 / 1→10 / 10→100 三阶段全生命周期）" 工作流。

一句话: 从「商家决定把抖音直播当经营阵地」到「拥有一个流量结构健康、能稳定月销的直播间」的全生命周期路径 —— 跨度数月到一年以上，是 intake 点名的两大主干工作流之一。

入门 SOP 共 5 步, 失败模式自检 5 项。

相关心智模型:
  • 算法生意：直播间是做给算法看的，不是做给用户看的: 抖音直播带货的本质是「向推荐算法证明这个直播间值得被推流」——理解算法如何用停留 / 转化 / GPM 这组指标分配免费流量，比话术技巧更底层；流量是非线性「大爆发」的，核心变量是流量 × 选品。
  • 承接 > 引流：流量是放大器不是发动机: 直播间能不能做起来，发动机是「承接能力」(UV 价值 / 停留时长 / GPM / 品组 / 话术)，流量 (自然 + 投流) 只是把这台发动机的输出放大——承接是负数时，加流量等于加速亏钱。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**入驻 + 基建（第 1 周）**: 注册抖音小店（个体工商户营业执照 + 缴店铺保证金），可绑定多个抖音账号实现 0 粉开播；完成主播实名认证（身份证+人脸，开播权限前提）；搭直播间（补光灯/麦克风/支架/功能分区）；组团队（最少 4 人：运营/场控/主播/助理）。**跳过会发生什么**：无营业执照/未实名无法开播；团队不齐则一人多岗、动作变形。 evidence: [T03-S002, T03-S006]"
  "**0→1 冷启动期（第 1 周～约 1 个月，目标月销百万级）**: 跑通「流量进来→留得住→转化掉」正循环。打法 = 货上亏钱留人（福利款占比高，约 80%）+ 抓停留和转化两个核心指标 + 投放加速。不追求销售额和利润率，只追账号标签精准化。**跳过会发生什么**：跳过冷启动直接追 GMV，则账号标签泛、后续流量进来都不转化，越投越亏。 evidence: [T03-S006, T03-S008]"
  "**1→10 增长/拉升期（约 1-3 个月，目标月销千万级）**: 爆品主推款占比上升（约 70%），同时关注人气/互动/停留/关注 + 转化率/销售额；流量上靠「短视频 + 自然流量」双驱动；用付费撬免费，免费流量提升转化后让标签更精准，再带来更多免费流量。**跳过会发生什么**：拉升期不上短视频端、只靠直播推荐，流量天花板很快到顶。 evidence: [T03-S006, T03-S008]"
  "**10→100 稳定/放大期（约 3-6 个月+，月销千万以上）**: 各分层产品数据均衡，重点转向「直播间整体数据 + 供应链 + 售前售后服务」；流量上引入「付费流量 + 短视频 + 自然流量」三条腿，付费占比上升。**跳过会发生什么**：放大期供应链跟不上则爆单即翻车（缺货/发货慢/退货率飙升）。 evidence: [T03-S006, T03-S008]"
  "**持续迭代（贯穿全程）**: 每场直播按 workflow 1 跑 + 复盘；把直播切片成短视频二次分发；坚持稳定开播频次（每周 3+ 场，二手测算第 8 周 GMV 可显著增长）。**跳过会发生什么**：开播不稳定则算法无法积累账号权重，每次开播都像重新冷启动。 evidence: [T03-S006]"
)
declare -a FAILURE_MODES=(
  "**0→1 没跑通就盲目矩阵化**: 触发原因 —— 以为多开号能多拿量。后果 —— 同主体账号在同一用户池互相抢量，每个直播间流量都稀薄，钱花了号都没起来。怎么避免：**先把一个账号跑到稳定月销，验证 SOP 可复制，再做有明确分工的矩阵；不要在 0→1 阶段开第二个号**。 evidence: [T03-S008]"
  "**供应链短板 —— 爆单即翻车**: 触发原因 —— 入驻时只看流量打法、不看供应链，线下厂商尤其「盲目自信」。后果 —— 10→100 放大期一爆单就缺货/发货慢/退货率飙升，号被限流。怎么避免：**入驻前就确认供应链能扛住放大期的量级和退换货，把「货是天花板」当铁律，供应链优势比流量技巧更核心**。 evidence: [T03-S001, T03-S008]"
  "**心态失衡 —— 把直播当「弯道超车」**: 触发原因 —— 用「卖货要即时回报」的心态做需要长期布局的事。后果 —— 投产不佳就摇摆、延迟投入、错失早期红利。怎么避免：**入驻时就做预期管理（「心流管理」），初期主动降低预期、长期投入，认知到品牌和卖货是两件事**。 evidence: [T03-S001, T03-S008]"
  "**运营人才短缺 —— 招到的都是「庸才」**: 触发原因 —— 优秀操盘手倾向自己创业而非受雇。后果 —— 品牌组不起高效团队，整个生命周期推进慢。怎么避免：**接受「招不到顶级操盘手」是常态，靠 SOP 化 + 官方课程培训现有团队补齐，不要把整盘生意压在「找到一个神操盘手」上**。 evidence: [T03-S008]"
  "**CLI 化暗示 (v0.6+)**: 可抽进 \`cli/workflow/merchant-lifecycle.sh\`，每条 failure 变 yes/no 检查项（如「你当前账号 0→1 跑通了吗？跑通前不要开第二个号」「你的供应链能扛住月销翻 10 倍吗？」）。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "0-1-1-10-10-100-walkthrough"
fi
